<template>
  <div>
    <a-card style="width: 100%;border-radius: 20px" class="mt-4 p-0">
      <h5 class="font-weight-bold">Shipping Information</h5>
      <div class="row mt-4">
        <div class="col-6">
        <span v-if="addressList.length === 0" @click="addressModel = true" style="color: #00aced; font-size: 12px" class="pointer">+ Add new address</span>
        </div>
        <div class="col-6 text-right">

        </div>
      </div>
    </a-card>
    <Address :modelOpen="addressModel" @closeModel="addressModel = false"/>
  </div>
</template>

<script>
import Address from "@/components/cart/Address";
import {mapGetters} from "vuex";

export default {
  name: "Shipping",
  components: {Address},
  data() {
    return {
      addressModel: false
    }
  },
  created() {
    if (!this.addressList.length > 0) this.$store.dispatch('ADDRESS_LIST');
  },
  computed: {
    ...mapGetters(["addressList"])
  }
}
</script>

